"use strict";(globalThis.webpackChunklearncpp_docs=globalThis.webpackChunklearncpp_docs||[]).push([[9365],{25400(n,r,t){t.r(r),t.d(r,{assets:()=>d,contentTitle:()=>l,default:()=>c,frontMatter:()=>o,metadata:()=>e,toc:()=>p});const e=JSON.parse('{"id":"cpp17/invoke-apply","title":"std::invoke \u4e0e std::apply (\u7edf\u4e00\u8c03\u7528\u4e0e\u5143\u7ec4\u5c55\u5f00)","description":"C++17 std::invoke \u4e0e std::apply (\u7edf\u4e00\u8c03\u7528\u4e0e\u5143\u7ec4\u5c55\u5f00) \u6559\u5b66\u793a\u4f8b","source":"@site/docs/cpp17/45-invoke-apply.md","sourceDirName":"cpp17","slug":"/cpp17/45-invoke-apply","permalink":"/LearnModernCpp/docs/cpp17/45-invoke-apply","draft":false,"unlisted":false,"tags":[{"inline":true,"label":"cpp17","permalink":"/LearnModernCpp/docs/tags/cpp-17"},{"inline":true,"label":"invoke_apply","permalink":"/LearnModernCpp/docs/tags/invoke-apply"}],"version":"current","sidebarPosition":46,"frontMatter":{"sidebar_position":46,"slug":"45-invoke-apply","title":"std::invoke \u4e0e std::apply (\u7edf\u4e00\u8c03\u7528\u4e0e\u5143\u7ec4\u5c55\u5f00)","description":"C++17 std::invoke \u4e0e std::apply (\u7edf\u4e00\u8c03\u7528\u4e0e\u5143\u7ec4\u5c55\u5f00) \u6559\u5b66\u793a\u4f8b","tags":["cpp17","invoke_apply"]},"sidebar":"docs","previous":{"title":"std::byte (\u7c7b\u578b\u5b89\u5168\u5b57\u8282)","permalink":"/LearnModernCpp/docs/cpp17/44-byte"},"next":{"title":"std::filesystem (\u6587\u4ef6\u7cfb\u7edf\u5e93)","permalink":"/LearnModernCpp/docs/cpp17/50-filesystem"}}');var a=t(74848),s=t(28453);const o={sidebar_position:46,slug:"45-invoke-apply",title:"std::invoke \u4e0e std::apply (\u7edf\u4e00\u8c03\u7528\u4e0e\u5143\u7ec4\u5c55\u5f00)",description:"C++17 std::invoke \u4e0e std::apply (\u7edf\u4e00\u8c03\u7528\u4e0e\u5143\u7ec4\u5c55\u5f00) \u6559\u5b66\u793a\u4f8b",tags:["cpp17","invoke_apply"]},l="std::invoke \u4e0e std::apply (\u7edf\u4e00\u8c03\u7528\u4e0e\u5143\u7ec4\u5c55\u5f00)",d={},p=[{value:"\u5b8c\u6574\u6e90\u7801",id:"\u5b8c\u6574\u6e90\u7801",level:2},{value:"\u53c2\u8003\u94fe\u63a5",id:"\u53c2\u8003\u94fe\u63a5",level:2}];function u(n){const r={a:"a",code:"code",h1:"h1",h2:"h2",header:"header",li:"li",p:"p",pre:"pre",ul:"ul",...(0,s.R)(),...n.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(r.header,{children:(0,a.jsx)(r.h1,{id:"stdinvoke-\u4e0e-stdapply-\u7edf\u4e00\u8c03\u7528\u4e0e\u5143\u7ec4\u5c55\u5f00",children:"std::invoke \u4e0e std::apply (\u7edf\u4e00\u8c03\u7528\u4e0e\u5143\u7ec4\u5c55\u5f00)"})}),"\n",(0,a.jsx)(r.p,{children:"C++17 \u6807\u51c6\u5f15\u5165\u7684 std::invoke \u4e0e std::apply (\u7edf\u4e00\u8c03\u7528\u4e0e\u5143\u7ec4\u5c55\u5f00) \u7279\u6027\u5b8c\u6574\u6559\u5b66\u793a\u4f8b\u3002"}),"\n",(0,a.jsx)(r.h2,{id:"\u5b8c\u6574\u6e90\u7801",children:"\u5b8c\u6574\u6e90\u7801"}),"\n",(0,a.jsx)(r.pre,{children:(0,a.jsx)(r.code,{className:"language-cpp",metastring:'title="cpp17/45_invoke_apply.cpp"',children:'/**\r\n * ============================================================\r\n * \u7279\u6027\u540d\u79f0: std::invoke \u4e0e std::apply (\u7edf\u4e00\u8c03\u7528\u4e0e\u5143\u7ec4\u5c55\u5f00)\r\n * \u6240\u5c5e\u6807\u51c6: C++17\r\n * ============================================================\r\n *\r\n * [\u662f\u4ec0\u4e48]: std::invoke \u63d0\u4f9b\u7edf\u4e00\u7684\u65b9\u5f0f\u8c03\u7528\u4efb\u4f55\u53ef\u8c03\u7528\u5bf9\u8c61\uff08\u51fd\u6570\u3001\r\n *          \u6210\u5458\u51fd\u6570\u3001\u51fd\u6570\u5bf9\u8c61\u3001lambda\uff09\u3002std::apply \u5c06 tuple\r\n *          \u7684\u5143\u7d20\u5c55\u5f00\u4e3a\u51fd\u6570\u53c2\u6570\u5e76\u8c03\u7528\u3002\r\n *\r\n * [\u4e3a\u4ec0\u4e48\u5f15\u5165]: C++ \u4e2d\u8c03\u7528\u51fd\u6570\u3001\u6210\u5458\u51fd\u6570\u3001\u51fd\u6570\u5bf9\u8c61\u7684\u8bed\u6cd5\u5404\u4e0d\u76f8\u540c\u3002\r\n *              std::invoke \u7edf\u4e00\u4e86\u8c03\u7528\u8bed\u6cd5\uff0c\u8ba9\u6cdb\u578b\u4ee3\u7801\u4e0d\u7528\u533a\u5206\r\n *              \u53ef\u8c03\u7528\u5bf9\u8c61\u7684\u7c7b\u578b\u3002std::apply \u89e3\u51b3\u4e86\u5c06 tuple \u5c55\u5f00\r\n *              \u4e3a\u53c2\u6570\u5217\u8868\u7684\u9700\u6c42\u3002\r\n *\r\n * [\u5173\u952e\u8981\u70b9]:\r\n *   - invoke(f, args...) \u2014\u2014 f \u53ef\u4ee5\u662f\u51fd\u6570/\u6210\u5458\u51fd\u6570/\u51fd\u6570\u5bf9\u8c61\r\n *   - \u6210\u5458\u51fd\u6570: invoke(&Class::method, object, args...)\r\n *   - \u6210\u5458\u53d8\u91cf: invoke(&Class::member, object)\r\n *   - apply(f, tuple) \u2014\u2014 \u5c06 tuple \u5c55\u5f00\u540e\u8c03\u7528 f\r\n *   - apply \u914d\u5408 make_from_tuple \u53ef\u4ee5\u7528 tuple \u6784\u9020\u5bf9\u8c61\r\n * ============================================================\r\n */\r\n\r\n#include <iostream>\r\n#include <functional>   // std::invoke\r\n#include <tuple>        // std::apply, std::make_from_tuple\r\n#include <string>\r\n#include <vector>\r\n#include <utility>\r\n\r\n// ============================================================\r\n// \u6d4b\u8bd5\u7528\u7684\u7c7b\u548c\u51fd\u6570\r\n// ============================================================\r\n\r\n// \u666e\u901a\u51fd\u6570\r\nint add(int a, int b) {\r\n    return a + b;\r\n}\r\n\r\n// \u7c7b\r\nstruct Calculator {\r\n    std::string name;\r\n    int base;\r\n\r\n    int multiply(int a, int b) const {\r\n        return a * b + base;\r\n    }\r\n\r\n    static int static_add(int a, int b) {\r\n        return a + b;\r\n    }\r\n\r\n    int operator()(int x) const {\r\n        return x * x + base;\r\n    }\r\n};\r\n\r\n// ============================================================\r\n// \u57fa\u7840\u7528\u6cd5\r\n// ============================================================\r\nvoid basic_usage() {\r\n    std::cout << "--- basic_usage ---\\n";\r\n\r\n    // ---- std::invoke ----\r\n\r\n    // 1. \u8c03\u7528\u666e\u901a\u51fd\u6570\r\n    auto r1 = std::invoke(add, 3, 4);\r\n    std::cout << "\u666e\u901a\u51fd\u6570: add(3,4) = " << r1 << "\\n";\r\n\r\n    // 2. \u8c03\u7528 lambda\r\n    auto lambda = [](int x, int y) { return x - y; };\r\n    auto r2 = std::invoke(lambda, 10, 3);\r\n    std::cout << "lambda: (10,3) = " << r2 << "\\n";\r\n\r\n    // 3. \u8c03\u7528\u6210\u5458\u51fd\u6570\r\n    Calculator calc{"\u8ba1\u7b97\u5668", 0};\r\n    auto r3 = std::invoke(&Calculator::multiply, calc, 5, 6);\r\n    std::cout << "\u6210\u5458\u51fd\u6570: multiply(5,6) = " << r3 << "\\n";\r\n\r\n    // 4. \u8c03\u7528\u6210\u5458\u51fd\u6570\uff08\u901a\u8fc7\u6307\u9488\uff09\r\n    Calculator* pcalc = &calc;\r\n    auto r4 = std::invoke(&Calculator::multiply, pcalc, 3, 4);\r\n    std::cout << "\u6210\u5458\u51fd\u6570(\u6307\u9488): multiply(3,4) = " << r4 << "\\n";\r\n\r\n    // 5. \u8bbf\u95ee\u6210\u5458\u53d8\u91cf\r\n    auto name = std::invoke(&Calculator::name, calc);\r\n    std::cout << "\u6210\u5458\u53d8\u91cf: name = " << name << "\\n";\r\n\r\n    // 6. \u8c03\u7528\u51fd\u6570\u5bf9\u8c61\uff08operator()\uff09\r\n    Calculator square_calc{"\u5e73\u65b9\u5668", 10};\r\n    auto r5 = std::invoke(square_calc, 5);\r\n    std::cout << "\u51fd\u6570\u5bf9\u8c61: (5) = " << r5 << " (5*5+10)\\n";\r\n\r\n    // 7. \u8c03\u7528\u9759\u6001\u6210\u5458\u51fd\u6570\r\n    auto r6 = std::invoke(&Calculator::static_add, 7, 8);\r\n    std::cout << "\u9759\u6001\u6210\u5458\u51fd\u6570: static_add(7,8) = " << r6 << "\\n";\r\n\r\n    // ---- std::apply ----\r\n\r\n    std::cout << "\\n";\r\n\r\n    // 8. \u5c06 tuple \u5c55\u5f00\u4e3a\u51fd\u6570\u53c2\u6570\r\n    auto args = std::make_tuple(10, 20);\r\n    auto r7 = std::apply(add, args);\r\n    std::cout << "apply(add, {10,20}) = " << r7 << "\\n";\r\n\r\n    // 9. \u7528 tuple \u8c03\u7528 lambda\r\n    auto concat = [](const std::string& a, const std::string& b) {\r\n        return a + " " + b;\r\n    };\r\n    auto str_args = std::make_tuple(std::string("Hello"), std::string("World"));\r\n    auto r8 = std::apply(concat, str_args);\r\n    std::cout << "apply(concat, {\\"Hello\\",\\"World\\"}) = " << r8 << "\\n";\r\n}\r\n\r\n// ============================================================\r\n// \u8fdb\u9636\u7528\u6cd5\r\n// ============================================================\r\n\r\n// 1. \u6cdb\u578b\u8c03\u7528\u5305\u88c5\u5668 \u2014\u2014 invoke \u8ba9\u6cdb\u578b\u4ee3\u7801\u7b80\u6d01\r\ntemplate<typename Callable, typename... Args>\r\nauto timed_call(Callable&& func, Args&&... args) {\r\n    std::cout << "  [\u8c03\u7528\u5f00\u59cb]\\n";\r\n    auto result = std::invoke(std::forward<Callable>(func),\r\n                              std::forward<Args>(args)...);\r\n    std::cout << "  [\u8c03\u7528\u7ed3\u675f]\\n";\r\n    return result;\r\n}\r\n\r\n// 2. \u7528 apply \u5b9e\u73b0 tuple \u7684 for_each\r\ntemplate<typename Tuple, typename Func>\r\nvoid tuple_for_each(const Tuple& t, Func&& func) {\r\n    std::apply([&func](const auto&... args) {\r\n        (func(args), ...);  // \u6298\u53e0\u8868\u8fbe\u5f0f\r\n    }, t);\r\n}\r\n\r\n// 3. \u7528 apply \u5c06 tuple \u8f6c\u4e3a\u5b57\u7b26\u4e32\r\ntemplate<typename... Args>\r\nstd::string tuple_to_string(const std::tuple<Args...>& t) {\r\n    std::string result = "(";\r\n    bool first = true;\r\n    std::apply([&result, &first](const auto&... args) {\r\n        auto append = [&](const auto& arg) {\r\n            if (!first) result += ", ";\r\n            first = false;\r\n            if constexpr (std::is_same_v<std::decay_t<decltype(arg)>, std::string>) {\r\n                result += "\\"" + arg + "\\"";\r\n            } else {\r\n                result += std::to_string(arg);\r\n            }\r\n        };\r\n        (append(args), ...);\r\n    }, t);\r\n    result += ")";\r\n    return result;\r\n}\r\n\r\n// 4. make_from_tuple \u2014\u2014 \u7528 tuple \u6784\u9020\u5bf9\u8c61\r\nstruct Point3D {\r\n    double x, y, z;\r\n    Point3D(double x, double y, double z) : x(x), y(y), z(z) {}\r\n    void print() const {\r\n        std::cout << "Point3D(" << x << ", " << y << ", " << z << ")\\n";\r\n    }\r\n};\r\n\r\n// 5. \u5ef6\u8fdf\u8c03\u7528 \u2014\u2014 \u5b58\u50a8\u51fd\u6570\u548c\u53c2\u6570\uff0c\u7a0d\u540e\u8c03\u7528\r\ntemplate<typename Func, typename... Args>\r\nauto make_deferred(Func&& func, Args&&... args) {\r\n    // \u5c06\u51fd\u6570\u548c\u53c2\u6570\u6253\u5305\u5230 tuple \u4e2d\r\n    auto package = std::make_tuple(std::forward<Func>(func),\r\n                                    std::forward<Args>(args)...);\r\n    return [package = std::move(package)]() mutable {\r\n        return std::apply([](auto&& func, auto&&... args) {\r\n            return std::invoke(std::forward<decltype(func)>(func),\r\n                              std::forward<decltype(args)>(args)...);\r\n        }, std::move(package));\r\n    };\r\n}\r\n\r\nvoid advanced_usage() {\r\n    std::cout << "\\n--- advanced_usage ---\\n";\r\n\r\n    // \u6cdb\u578b\u8c03\u7528\u5305\u88c5\u5668\r\n    std::cout << "\u8ba1\u65f6\u8c03\u7528\u666e\u901a\u51fd\u6570:\\n";\r\n    auto r1 = timed_call(add, 3, 4);\r\n    std::cout << "  \u7ed3\u679c: " << r1 << "\\n";\r\n\r\n    std::cout << "\u8ba1\u65f6\u8c03\u7528 lambda:\\n";\r\n    auto r2 = timed_call([](int x) { return x * x; }, 7);\r\n    std::cout << "  \u7ed3\u679c: " << r2 << "\\n";\r\n\r\n    // tuple_for_each\r\n    std::cout << "\\ntuple \u904d\u5386: ";\r\n    auto t = std::make_tuple(1, 2.5, std::string("hello"));\r\n    tuple_for_each(t, [](const auto& v) {\r\n        std::cout << v << " ";\r\n    });\r\n    std::cout << "\\n";\r\n\r\n    // tuple_to_string\r\n    auto t2 = std::make_tuple(42, 3.14, std::string("world"));\r\n    std::cout << "tuple \u8f6c\u5b57\u7b26\u4e32: " << tuple_to_string(t2) << "\\n";\r\n\r\n    // make_from_tuple\r\n    auto point_args = std::make_tuple(1.0, 2.0, 3.0);\r\n    auto point = std::make_from_tuple<Point3D>(point_args);\r\n    std::cout << "make_from_tuple: ";\r\n    point.print();\r\n\r\n    // \u5ef6\u8fdf\u8c03\u7528\r\n    auto deferred = make_deferred(add, 100, 200);\r\n    std::cout << "\u5ef6\u8fdf\u8c03\u7528\u7ed3\u679c: " << deferred() << "\\n";\r\n}\r\n\r\n// ============================================================\r\n// \u6613\u9519\u70b9 / \u9677\u9631\r\n// ============================================================\r\nvoid pitfalls() {\r\n    std::cout << "\\n--- pitfalls ---\\n";\r\n\r\n    // \u9677\u9631 1: invoke \u7684\u6210\u5458\u51fd\u6570\u8c03\u7528\u8bed\u6cd5\r\n    //   \u7b2c\u4e00\u4e2a\u53c2\u6570\u5fc5\u987b\u662f\u5bf9\u8c61\uff08\u503c/\u5f15\u7528/\u6307\u9488/\u667a\u80fd\u6307\u9488\uff09\r\n    Calculator calc{"\u6d4b\u8bd5", 0};\r\n    // std::invoke(&Calculator::multiply, 5, 6);  // \u9519\u8bef\uff01\u7f3a\u5c11\u5bf9\u8c61\r\n    auto r = std::invoke(&Calculator::multiply, calc, 5, 6);\r\n    std::cout << "\u9677\u96311 - \u6210\u5458\u51fd\u6570\u7b2c\u4e00\u4e2a\u53c2\u6570\u5fc5\u987b\u662f\u5bf9\u8c61: " << r << "\\n";\r\n\r\n    // \u9677\u9631 2: invoke \u4e0e reference_wrapper\r\n    Calculator calc2{"\u5f15\u7528\u6d4b\u8bd5", 100};\r\n    auto ref = std::ref(calc2);\r\n    auto r2 = std::invoke(&Calculator::multiply, ref, 3, 4);\r\n    std::cout << "\u9677\u96312 - reference_wrapper \u4e5f\u53ef\u4ee5: " << r2 << "\\n";\r\n\r\n    // \u9677\u9631 3: apply \u7684 tuple \u53c2\u6570\u6570\u91cf\u5fc5\u987b\u5339\u914d\u51fd\u6570\u53c2\u6570\u6570\u91cf\r\n    // auto bad_args = std::make_tuple(1, 2, 3);\r\n    // std::apply(add, bad_args);  // \u7f16\u8bd1\u9519\u8bef\uff01add \u53ea\u8981 2 \u4e2a\u53c2\u6570\r\n    std::cout << "\u9677\u96313 - apply \u7684 tuple \u5143\u7d20\u6570\u5fc5\u987b\u5339\u914d\u51fd\u6570\u53c2\u6570\u6570\\n";\r\n\r\n    // \u9677\u9631 4: invoke \u8fd4\u56de\u7c7b\u578b\r\n    //   \u5982\u679c\u8c03\u7528 void \u51fd\u6570\uff0cinvoke \u4e5f\u8fd4\u56de void\r\n    auto void_func = [](int x) { (void)x; };\r\n    std::invoke(void_func, 42);  // \u8fd4\u56de void\r\n    std::cout << "\u9677\u96314 - invoke \u7684\u8fd4\u56de\u7c7b\u578b\u8ddf\u968f\u88ab\u8c03\u7528\u51fd\u6570\\n";\r\n\r\n    // \u9677\u9631 5: apply \u4e0d\u80fd\u76f4\u63a5\u7528\u4e8e\u6210\u5458\u51fd\u6570\r\n    //   \u9700\u8981\u628a\u5bf9\u8c61\u653e\u5728 tuple \u7684\u7b2c\u4e00\u4e2a\u5143\u7d20\u4e2d\r\n    auto member_args = std::make_tuple(calc, 3, 4);\r\n    auto r3 = std::apply(&Calculator::multiply, member_args);\r\n    std::cout << "\u9677\u96315 - apply \u6210\u5458\u51fd\u6570\uff1a\u5bf9\u8c61\u653e tuple \u9996\u4f4d: " << r3 << "\\n";\r\n\r\n    // \u9677\u9631 6: std::invoke \u5728\u7f16\u8bd1\u671f\u7684\u68c0\u67e5\r\n    //   \u5982\u679c\u53ef\u8c03\u7528\u5bf9\u8c61\u548c\u53c2\u6570\u4e0d\u5339\u914d\uff0c\u4f1a\u5f97\u5230\u6e05\u6670\u7684\u7f16\u8bd1\u9519\u8bef\r\n    std::cout << "\u9677\u96316 - invoke \u63d0\u4f9b\u6e05\u6670\u7684\u7f16\u8bd1\u671f\u7c7b\u578b\u68c0\u67e5\\n";\r\n}\r\n\r\n// ============================================================\r\n// \u4e3b\u51fd\u6570\r\n// ============================================================\r\nint main() {\r\n    std::cout << "===== std::invoke \u4e0e std::apply - C++17 =====\\n\\n";\r\n\r\n    basic_usage();\r\n    advanced_usage();\r\n    pitfalls();\r\n\r\n    return 0;\r\n}\n'})}),"\n",(0,a.jsx)(r.h2,{id:"\u53c2\u8003\u94fe\u63a5",children:"\u53c2\u8003\u94fe\u63a5"}),"\n",(0,a.jsxs)(r.ul,{children:["\n",(0,a.jsx)(r.li,{children:(0,a.jsx)(r.a,{href:"https://en.cppreference.com/w/cpp/utility/functional/invoke",children:"cppreference: std::invoke \u4e0e std::apply (\u7edf\u4e00\u8c03\u7528\u4e0e\u5143\u7ec4\u5c55\u5f00)"})}),"\n"]})]})}function c(n={}){const{wrapper:r}={...(0,s.R)(),...n.components};return r?(0,a.jsx)(r,{...n,children:(0,a.jsx)(u,{...n})}):u(n)}},28453(n,r,t){t.d(r,{R:()=>o,x:()=>l});var e=t(96540);const a={},s=e.createContext(a);function o(n){const r=e.useContext(s);return e.useMemo(function(){return"function"==typeof n?n(r):{...r,...n}},[r,n])}function l(n){let r;return r=n.disableParentContext?"function"==typeof n.components?n.components(a):n.components||a:o(n.components),e.createElement(s.Provider,{value:r},n.children)}}}]);